// ─── Seed default templates ───
const seedDefaults = async () => {
  for (const tpl of defaultTemplates) {
    const exists = await Template.exists({ key: tpl.key.toLowerCase() });
    if (!exists) {
      await Template.create({ ...tpl, key: tpl.key.toLowerCase() })
        .catch((e) => console.warn(`Seed failed for "${tpl.key}":`, e.message));
    }
  }
};

// ─── Service functions ───
export const renderTemplate = async (key, variables = {}) => {
  await seedDefaults();
  const template = await Template.findOne({ key: key.toLowerCase() });
  if (!template) return `<p>Template "${key}" not found.</p>`;

  let html = template.html;
  Object.entries(variables).forEach(([varName, value]) => {
    html = html.replace(new RegExp(`\\{${varName}\\}`, 'g'), value || '');
  });
  return html;
};

export const getAllTemplates = async () => {
  await seedDefaults();
  const templates = await Template.find().sort('category key').lean();
  const result = {};
  templates.forEach(t => {
    result[t.key] = { subject: t.subject, html: t.html, variables: t.variables, category: t.category };
  });
  return result;
};

export const getTemplate = async (key) => {
  await seedDefaults();
  return Template.findOne({ key: key.toLowerCase() }).lean();
};

export const updateTemplate = async (key, data) => {
  await seedDefaults();
  return Template.findOneAndUpdate({ key: key.toLowerCase() }, { $set: data }, { new: true, upsert: true }).lean();
};

export const resetTemplate = async (key) => {
  await seedDefaults();
  const defaultTpl = defaultTemplates.find(
    t => t.key.toLowerCase() === key.toLowerCase()
  );
  if (!defaultTpl) return null;
  return Template.findOneAndUpdate({ key: key.toLowerCase() }, { $set: defaultTpl }, { new: true, upsert: true }).lean();
};

export const resetAllTemplatesToDefault = async () => {
  for (const tpl of defaultTemplates) {
    const existing = await Template.findOne({ key: tpl.key.toLowerCase() }).lean();

    if (!existing) {
      await Template.create({
        key: tpl.key.toLowerCase(),
        subject: tpl.subject,
        html: tpl.html,
        variables: tpl.variables,
        category: tpl.category,
      }).catch((e) => console.warn(`Reset create failed for "${tpl.key}":`, e.message));
    } else if (!existing.subject || existing.subject === "untitled" || existing.subject === "") {
      await Template.findOneAndUpdate(
        { key: tpl.key.toLowerCase() },
        { $set: {
          subject: tpl.subject,
          html: tpl.html,
          variables: tpl.variables,
          category: tpl.category,
        }},
        { new: true }
      );
    } else {
      await Template.findOneAndUpdate(
        { key: tpl.key.toLowerCase() },
        { $set: {
          key: tpl.key.toLowerCase(),
          variables: tpl.variables,
          category: tpl.category,
        }},
        { new: true }
      );
    }
  }
  console.log(`✅ All ${defaultTemplates.length} templates reset to defaults`);
};
